// --- types.d.ts ---
export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastDay[];
}

export interface ForecastItemProps extends ForecastDay {
  unit: string;
}

export interface HookReturn {
  formattedTemp: string;
  formattedHumidity: string;
  formattedWind: string;
  unit: string;
}


// --- constants.ts ---
import { ForecastDay } from './types';

export const WEATHER_ICONS: Record<string, ForecastDay['icon']> = {
  Sunny: '☀️',
  Cloudy: '☁️',
  Rainy: '🌧️',
  Snowy: '❄️',
  Stormy: '⛈️',
  'Partly Cloudy': '⛅',
  Clear: '☀️',
  Mist: '🌫️',
  Thunderstorm: '⛈️',
  Drizzle: '🌦️',
};

export const DEFAULT_UNIT = '°C';


// --- hooks.ts ---
import { useMemo } from 'react';
import { Props, HookReturn } from './types';

export const useWeather = (props: Props): HookReturn => {
  const { temperature, humidity, windSpeed, unit = 'C' } = props;

  return useMemo(() => {
    return {
      formattedTemp: `${Math.round(temperature)}°${unit}`,
      formattedHumidity: `${humidity}%`,
      formattedWind: `${windSpeed} km/h`,
      unit,
    };
  }, [temperature, humidity, windSpeed, unit]);
};


// --- ForecastItem.tsx ---
import React from 'react';
import { Box, Stack, Text } from '@ggui-ai/design/primitives';
import { ForecastItemProps } from './types';

/**
 * ForecastItem displays a single day's forecast details.
 * Uses Box for visual containment and Stack for layout.
 */
export const ForecastItem: React.FC<ForecastItemProps> = ({ day, icon, high, low, unit }) => {
  return (
    <Box 
      padding="var(--ggui-spacing-2, 8px)"
      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
      borderRadius="var(--ggui-shape-radius-md, 8px)"
    >
      <Stack gap="var(--ggui-spacing-1, 4px)" align="center">
        <Text 
          size="sm" 
          weight="semibold"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
          as="span"
          align="center"
        >
          {day}
        </Text>

        <Text size="3xl" as="span" align="center">
          {icon}
        </Text>

        <Stack gap={0} align="center">
          <Text size="sm" weight="bold" align="center">
            {Math.round(high)}°{unit}
          </Text>
          <Text 
            size="xs" 
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            align="center"
          >
            {Math.round(low)}°{unit}
          </Text>
        </Stack>
      </Stack>
    </Box>
  );
};


// --- ui.tsx ---
import React from 'react';
import { Card, Stack, Heading, Text, Container, Divider, Box } from '@ggui-ai/design/primitives';
import { Props } from './types';
import { useWeather } from './hooks';
import { ForecastItem } from './ForecastItem';
import { WEATHER_ICONS } from './constants';

export const WeatherCard: React.FC<Props> = (props) => {
  const { city, condition, forecast } = props;
  const { formattedTemp, formattedHumidity, formattedWind, unit } = useWeather(props);

  const weatherIcon = WEATHER_ICONS[condition] || '🌡️';

  return (
    <Container maxWidth="sm" padding={16}>
      <Card padding={32} shadow="md" radius="xl" border={false}>
        <Stack gap={32}>
          {/* Header Section */}
          <Stack direction="horizontal" justify="between" align="center">
            <Stack gap={4}>
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                {city}
              </Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {condition}
              </Text>
            </Stack>
            <Text 
              size="4xl" 
              as="span"
            >
              {weatherIcon}
            </Text>
          </Stack>

          {/* Hero Section - Large Temperature */}
          <Box paddingY={16}>
            <Stack align="center">
              <Text 
                size="4xl"
                weight="bold" 
                color="var(--ggui-color-primary-600, #0284c7)"
                align="center"
              >
                {formattedTemp}
              </Text>
            </Stack>
          </Box>

          {/* Detail Section - Humidity & Wind */}
          <Stack gap={0}>
            <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />
            <Box paddingY={24}>
              <Stack direction="horizontal" justify="around" align="center">
                <Stack align="center" gap={4}>
                  <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Humidity
                  </Text>
                  <Text weight="semibold" size="lg" color="var(--ggui-color-onSurface, #18181b)">
                    {formattedHumidity}
                  </Text>
                </Stack>

                <Divider orientation="vertical" margin={12} color="var(--ggui-color-outline, #d4d4d8)" />

                <Stack align="center" gap={4}>
                  <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Wind
                  </Text>
                  <Text weight="semibold" size="lg" color="var(--ggui-color-onSurface, #18181b)">
                    {formattedWind}
                  </Text>
                </Stack>
              </Stack>
            </Box>
            <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />
          </Stack>

          {/* Forecast Section */}
          <Stack gap={16}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Next Days
            </Text>
            <Stack direction="horizontal" gap={12} justify="between" wrap>
              {forecast.map((item, idx) => (
                <ForecastItem 
                  key={`${item.day}-${idx}`} 
                  {...item} 
                  unit={unit} 
                />
              ))}
            </Stack>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
};


// --- render.tsx ---
import { WeatherCard } from './ui';
import { Props } from './types';

export default function Render(props: Props) {
  return <WeatherCard {...props} />;
}
